document.addEventListener('DOMContentLoaded',()=>{const navbar=document.getElementById('navbar');window.addEventListener('scroll',()=>{navbar.classList.toggle('scrolled',window.scrollY>50);});const hamburger=document.getElementById('hamburger');const navLinks=document.getElementById('navLinks');hamburger.addEventListener('click',()=>{hamburger.classList.toggle('active');navLinks.classList.toggle('active');});navLinks.querySelectorAll('a').forEach(link=>{link.addEventListener('click',()=>{hamburger.classList.remove('active');navLinks.classList.remove('active');});});document.addEventListener('click',(e)=>{if (!navLinks.contains(e.target)&&!hamburger.contains(e.target)){hamburger.classList.remove('active');navLinks.classList.remove('active');}});document.querySelectorAll('a[href^="#"]').forEach(anchor=>{anchor.addEventListener('click',function (e){e.preventDefault();const target=document.querySelector(this.getAttribute('href'));if (target){target.scrollIntoView({behavior:'smooth',block:'start'});}});});const counters=document.querySelectorAll('.stat-number');const counterObserver=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if (entry.isIntersecting){const counter=entry.target;const target=parseInt(counter.getAttribute('data-target'));animateCounter(counter,target);counterObserver.unobserve(counter);}});},{threshold:0.5});counters.forEach(counter=>counterObserver.observe(counter));function animateCounter(element,target){const duration=2000;const start=0;const increment=target/(duration/16);let current=start;const timer=setInterval(()=>{current+=increment;if (current>=target){element.textContent=target.toLocaleString('id-ID');clearInterval(timer);}else{element.textContent=Math.floor(current).toLocaleString('id-ID');}},16);}const fadeElements=document.querySelectorAll('.service-card,.why-card,.location-card,.section-header');fadeElements.forEach(el=>el.classList.add('fade-in'));const fadeObserver=new IntersectionObserver((entries)=>{entries.forEach((entry,index)=>{if (entry.isIntersecting){setTimeout(()=>{entry.target.classList.add('visible');},index*80);fadeObserver.unobserve(entry.target);}});},{threshold:0.1,rootMargin:'0px 0px-50px 0px'});fadeElements.forEach(el=>fadeObserver.observe(el));const track=document.getElementById('testimonialTrack');const prevBtn=document.getElementById('prevTest');const nextBtn=document.getElementById('nextTest');const dotsContainer=document.getElementById('testimonialDots');const cards=track.querySelectorAll('.testimonial-card');let currentIndex=0;let autoSlide;cards.forEach((_,i)=>{const dot=document.createElement('div');dot.classList.add('dot');if (i===0) dot.classList.add('active');dot.addEventListener('click',()=>goToSlide(i));dotsContainer.appendChild(dot);});function getCardWidth(){const card=cards[0];const style=getComputedStyle(track);const gap=parseInt(style.gap)||24;return card.offsetWidth+gap;}function updateDots(){dotsContainer.querySelectorAll('.dot').forEach((dot,i)=>{dot.classList.toggle('active',i===currentIndex);});}function goToSlide(index){if (index<0) index=cards.length-1;if (index>=cards.length) index=0;currentIndex=index;track.scrollTo({left:getCardWidth()*currentIndex,behavior:'smooth'});updateDots();}prevBtn.addEventListener('click',()=>goToSlide(currentIndex-1));nextBtn.addEventListener('click',()=>goToSlide(currentIndex+1));function startAutoSlide(){autoSlide=setInterval(()=>goToSlide(currentIndex+1),5000);}function stopAutoSlide(){clearInterval(autoSlide);}startAutoSlide();track.addEventListener('mouseenter',stopAutoSlide);track.addEventListener('mouseleave',startAutoSlide);let touchStartX=0;let touchEndX=0;track.addEventListener('touchstart',(e)=>{touchStartX=e.changedTouches[0].screenX;stopAutoSlide();},{passive:true});track.addEventListener('touchend',(e)=>{touchEndX=e.changedTouches[0].screenX;const diff=touchStartX-touchEndX;if (Math.abs(diff)>50){diff>0?goToSlide(currentIndex+1):goToSlide(currentIndex-1);}startAutoSlide();},{passive:true});const sections=document.querySelectorAll('section[id]');const sectionObserver=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if (entry.isIntersecting){const id=entry.target.getAttribute('id');document.querySelectorAll('.nav-links a').forEach(link=>{link.classList.remove('active');if (link.getAttribute('href')===`#${id}`){link.classList.add('active');}});}});},{threshold:0.3});sections.forEach(section=>sectionObserver.observe(section));window.addEventListener('scroll',()=>{const scrollY=window.scrollY;document.querySelectorAll('.shape').forEach((shape,i)=>{const speed=(i+1)*0.02;shape.style.transform=`translateY(${scrollY*speed}px)`;});});console.log('🦷 Lumie Dental Website loaded successfully!');});